    # ==========================================================
    # PROJECTED SALES DASHBOARD CONFIG
    # ==========================================================
    PSD_PROJECT_START_DATE = date(2026, 4, 25)
    PSD_PROJECT_YEARS = 3

    PSD_PROJECT_END_DATE = date(
        PSD_PROJECT_START_DATE.year + PSD_PROJECT_YEARS,
        PSD_PROJECT_START_DATE.month,
        PSD_PROJECT_START_DATE.day,
    ) - timedelta(days=1)

    PSD_TOTAL_FLATS_TARGET = 588

    PSD_GOOD_DAY_WEIGHT = 1.25
    PSD_NORMAL_DAY_WEIGHT = 1.0
    PSD_BAD_DAY_WEIGHT = 0.0

    # ==========================================================
    # PROJECTED SALES UTILITIES
    # ==========================================================
    def psd_month_start(d: date) -> date:
        return date(d.year, d.month, 1)

    def psd_next_month(d: date) -> date:
        return date(d.year + (d.month // 12), (d.month % 12) + 1, 1)

    def psd_add_months(d: date, n: int) -> date:
        y = d.year + (d.month - 1 + n) // 12
        m = (d.month - 1 + n) % 12 + 1
        return date(y, m, 1)

    def psd_iter_days(s: date, e: date):
        cur = s

        while cur <= e:
            yield cur
            cur += timedelta(days=1)

    def psd_month_label(d: date) -> str:
        return d.strftime("%B %y").upper()

    def psd_parse_month_label(val: str) -> Optional[Tuple[int, int]]:
        if val is None:
            return None

        s = str(val).strip()

        if not s or s.lower() == "nan":
            return None

        s_norm = " ".join(s.replace("-", " ").split())

        for fmt in ("%B %y", "%b %y", "%B %Y", "%b %Y"):
            try:
                dt = dt_datetime.strptime(s_norm.title(), fmt)
                return (dt.year, dt.month)
            except Exception:
                continue

        return None

    def psd_quarter_start(d: date) -> date:
        q_m = ((d.month - 1) // 3) * 3 + 1
        return date(d.year, q_m, 1)

    def psd_quarter_end(d: date) -> date:
        qs = psd_quarter_start(d)
        return psd_add_months(qs, 3) - timedelta(days=1)

    # ==========================================================
    # AMAVASYA APPROXIMATION
    # ==========================================================
    def psd_to_jd(dt_utc: datetime) -> float:
        year, month, day = dt_utc.year, dt_utc.month, dt_utc.day

        hour = (
            dt_utc.hour
            + dt_utc.minute / 60
            + dt_utc.second / 3600
            + dt_utc.microsecond / 3_600_000_000
        )

        if month <= 2:
            year -= 1
            month += 12

        A = year // 100
        B = 2 - A + (A // 4)

        jd0 = (
            int(365.25 * (year + 4716))
            + int(30.6001 * (month + 1))
            + day
            + B
            - 1524.5
        )

        return jd0 + hour / 24.0

    def psd_from_jd(jd: float) -> datetime:
        jd += 0.5
        Z = int(jd)
        F = jd - Z

        if Z < 2299161:
            A = Z
        else:
            alpha = int((Z - 1867216.25) / 36524.25)
            A = Z + 1 + alpha - int(alpha / 4)

        B = A + 1524
        C = int((B - 122.1) / 365.25)
        D = int(365.25 * C)
        E = int((B - D) / 30.6001)

        day = B - D - int(30.6001 * E) + F
        month = E - 1 if E < 14 else E - 13
        year = C - 4716 if month > 2 else C - 4715

        day_int = int(day)
        frac = day - day_int

        hours = frac * 24
        h = int(hours)

        minutes = (hours - h) * 60
        m = int(minutes)

        seconds = (minutes - m) * 60
        s = int(seconds)

        micros = int((seconds - s) * 1_000_000)

        return dt_datetime(
            year,
            month,
            day_int,
            h,
            m,
            s,
            micros,
            tzinfo=timezone.utc,
        )

    def psd_approx_new_moon_jde(k: float) -> float:
        return (
            2451550.09765
            + 29.530588853 * k
            + 0.0001337 * (k ** 2)
            - 0.000000150 * (k ** 3)
            + 0.00000000073 * (k ** 4)
        )

    def psd_get_amavasya_dates_ist(start: date, end: date) -> List[date]:
        ist_offset = timedelta(hours=5, minutes=30)

        start_dt_utc = dt_datetime(
            start.year,
            start.month,
            start.day,
            tzinfo=timezone.utc,
        )

        end_dt_utc = dt_datetime(
            end.year,
            end.month,
            end.day,
            23,
            59,
            59,
            tzinfo=timezone.utc,
        )

        jd_start = psd_to_jd(start_dt_utc)
        jd_end = psd_to_jd(end_dt_utc)

        k_start = (jd_start - 2451550.09765) / 29.530588853
        k_end = (jd_end - 2451550.09765) / 29.530588853

        ks = math.floor(k_start) - 2
        ke = math.ceil(k_end) + 2

        out = set()

        for k in range(ks, ke + 1):
            jde = psd_approx_new_moon_jde(k)
            dt_utc = psd_from_jd(jde)
            d_ist = (dt_utc + ist_offset).date()

            if start <= d_ist <= end:
                out.add(d_ist)

        return sorted(out)

    # ==========================================================
    # FESTIVALS MODEL
    # ==========================================================
    @dataclass(frozen=True)
    class psd_FestDay:
        name: str
        d: date
        kind: str  # GOOD | BAD | HOLIDAY | INFO

    def psd_add_range(out: List[psd_FestDay], name: str, s: date, e: date, kind: str):
        cur = s

        while cur <= e:
            out.append(psd_FestDay(name, cur, kind))
            cur += timedelta(days=1)

    def psd_fixed_public_holidays(start: date, end: date) -> List[psd_FestDay]:
        out: List[psd_FestDay] = []

        for y in range(start.year, end.year + 1):
            fixed = [
                ("New Year", date(y, 1, 1)),
                ("Republic Day", date(y, 1, 26)),
                ("Shivaji Jayanti (MH)", date(y, 2, 19)),
                ("Ambedkar Jayanti", date(y, 4, 14)),
                ("Maharashtra Day", date(y, 5, 1)),
                ("Independence Day", date(y, 8, 15)),
                ("Gandhi Jayanti", date(y, 10, 2)),
                ("Christmas", date(y, 12, 25)),
            ]

            for n, d in fixed:
                if start <= d <= end:
                    out.append(psd_FestDay(n, d, "HOLIDAY"))

        return out

    def psd_festival_days_between(start: date, end: date) -> List[psd_FestDay]:
        f: List[psd_FestDay] = []

        GOOD_DATES: Dict[int, List[Tuple[str, date]]] = {
            2026: [
                ("Nag Panchami", date(2026, 8, 17)),
                ("Onam", date(2026, 8, 26)),
                ("Ganesh Chaturthi / Ganesh Sthapana", date(2026, 9, 14)),
                ("Dhanteras", date(2026, 10, 29)),
                ("Diwali (Lakshmi Puja)", date(2026, 10, 31)),
            ],
            2027: [
                ("Makar Sankranti", date(2027, 1, 15)),
                ("Pongal", date(2027, 1, 15)),
                ("Vasant Panchami", date(2027, 2, 11)),
                ("Mahashivratri", date(2027, 3, 6)),
                ("Holika Dahan (before Holi)", date(2027, 3, 21)),
                ("Ugadi", date(2027, 4, 7)),
                ("Gudi Padwa", date(2027, 4, 7)),
                ("Chaitra Navratri Begins", date(2027, 4, 7)),
                ("Ram Navami", date(2027, 4, 15)),
                ("Akshaya Tritiya", date(2027, 5, 9)),
                ("Nag Panchami", date(2027, 8, 6)),
                ("Ganesh Chaturthi / Ganesh Sthapana", date(2027, 9, 4)),
                ("Onam", date(2027, 9, 12)),
                ("Dhanteras", date(2027, 10, 27)),
                ("Diwali (Lakshmi Puja)", date(2027, 10, 29)),
            ],
            2028: [
                ("Makar Sankranti", date(2028, 1, 15)),
                ("Pongal", date(2028, 1, 15)),
                ("Vasant Panchami", date(2028, 1, 31)),
                ("Mahashivratri", date(2028, 2, 23)),
                ("Holika Dahan (before Holi)", date(2028, 3, 10)),
                ("Ugadi", date(2028, 3, 27)),
                ("Gudi Padwa", date(2028, 3, 27)),
                ("Chaitra Navratri Begins", date(2028, 3, 27)),
                ("Ram Navami", date(2028, 4, 3)),
                ("Akshaya Tritiya", date(2028, 4, 27)),
                ("Nag Panchami", date(2028, 7, 26)),
                ("Ganesh Chaturthi / Ganesh Sthapana", date(2028, 8, 23)),
                ("Onam", date(2028, 9, 1)),
                ("Dhanteras", date(2028, 10, 15)),
                ("Diwali (Lakshmi Puja)", date(2028, 10, 17)),
            ],
            2029: [
                ("Makar Sankranti", date(2029, 1, 14)),
                ("Pongal", date(2029, 1, 14)),
                ("Vasant Panchami", date(2029, 1, 19)),
                ("Mahashivratri", date(2029, 2, 11)),
                ("Holika Dahan (before Holi)", date(2029, 2, 28)),
                ("Ugadi", date(2029, 4, 14)),
                ("Gudi Padwa", date(2029, 4, 14)),
                ("Chaitra Navratri Begins", date(2029, 4, 14)),
                ("Ram Navami", date(2029, 4, 23)),
            ],
        }

        for y, items in GOOD_DATES.items():
            for name, d in items:
                if start <= d <= end:
                    f.append(psd_FestDay(name, d, "GOOD"))

        # Baisakhi approx fixed
        for y in range(start.year, end.year + 1):
            d = date(y, 4, 13)

            if start <= d <= end:
                f.append(psd_FestDay("Baisakhi", d, "GOOD"))

        # Chaitra Navratri windows
        for y in [2027, 2028, 2029]:
            begins = next(
                (
                    d for (n, d) in GOOD_DATES.get(y, [])
                    if "Chaitra Navratri Begins" in n
                ),
                None,
            )

            if begins and start <= begins <= end:
                psd_add_range(
                    f,
                    "Chaitra Navratri",
                    begins,
                    begins + timedelta(days=8),
                    "GOOD",
                )

        # Sharad Navratri + Dussehra
        sharad_starts = {
            2026: date(2026, 10, 11),
            2027: date(2027, 9, 30),
            2028: date(2028, 9, 19),
        }

        for y, d in sharad_starts.items():
            if start <= d <= end:
                psd_add_range(
                    f,
                    "Sharad Navratri",
                    d,
                    d + timedelta(days=8),
                    "GOOD",
                )

                dus = d + timedelta(days=9)

                if start <= dus <= end:
                    f.append(psd_FestDay("Dussehra / Vijayadashami", dus, "GOOD"))

        # Shravan Maas season
        for y in range(start.year, end.year + 1):
            ss, ee = date(y, 8, 1), date(y, 8, 31)
            s = max(ss, start)
            e = min(ee, end)

            if s <= e:
                psd_add_range(f, "Shravan Maas (season)", s, e, "GOOD")

        # Pitru Paksha
        pitru = {
            2026: (date(2026, 9, 27), date(2026, 10, 10)),
            2027: (date(2027, 9, 16), date(2027, 9, 29)),
            2028: (date(2028, 9, 4), date(2028, 9, 17)),
        }

        for _, (ps, pe) in pitru.items():
            s = max(ps, start)
            e = min(pe, end)

            if s <= e:
                psd_add_range(f, "Pitru Paksha", s, e, "BAD")

        # Adhik Maas
        for s, e, nm in [
            (date(2026, 5, 17), date(2026, 6, 15), "Adhik Maas (Mal Maas)"),
            (date(2029, 3, 17), date(2029, 4, 13), "Adhik Maas (Mal Maas)"),
        ]:
            ss = max(s, start)
            ee = min(e, end)

            if ss <= ee:
                psd_add_range(f, nm, ss, ee, "BAD")

        # Amavasya
        for d in psd_get_amavasya_dates_ist(start, end):
            f.append(psd_FestDay("Amavasya", d, "BAD"))

        # Eclipses
        eclipse_bad = [
            ("Solar Eclipse", date(2026, 8, 12)),
            ("Lunar Eclipse", date(2026, 8, 28)),
            ("Solar Eclipse", date(2027, 2, 6)),
            ("Lunar Eclipse", date(2027, 2, 21)),
            ("Solar Eclipse", date(2027, 8, 2)),
            ("Lunar Eclipse", date(2027, 8, 17)),
            ("Lunar Eclipse", date(2028, 1, 12)),
            ("Solar Eclipse", date(2028, 1, 26)),
            ("Solar Eclipse", date(2029, 1, 14)),
        ]

        for nm, d in eclipse_bad:
            if start <= d <= end:
                f.append(psd_FestDay(nm, d, "BAD"))

        # Sankranti day except Jan
        for y in range(start.year, end.year + 1):
            for m in range(1, 13):
                if m == 1:
                    continue

                try:
                    d = date(y, m, 14)
                except ValueError:
                    continue

                if start <= d <= end:
                    f.append(psd_FestDay("Sankranti Day (approx)", d, "BAD"))

        # Public holidays
        f.extend(psd_fixed_public_holidays(start, end))

        # Clamp and sort
        f = [x for x in f if start <= x.d <= end]
        f.sort(key=lambda x: (x.d, x.kind, x.name))

        return f

    def psd_day_weight(d: date, by_date: Dict[date, List[psd_FestDay]]) -> float:
        items = by_date.get(d, [])

        if any(x.kind in ("BAD", "HOLIDAY") for x in items):
            return PSD_BAD_DAY_WEIGHT

        if any(x.kind == "GOOD" for x in items):
            return PSD_GOOD_DAY_WEIGHT

        return PSD_NORMAL_DAY_WEIGHT

    def psd_weighted_days(s: date, e: date, by_date: Dict[date, List[psd_FestDay]]) -> float:
        return sum(psd_day_weight(d, by_date) for d in psd_iter_days(s, e))

    def psd_selling_days_count(s: date, e: date, by_date: Dict[date, List[psd_FestDay]]) -> int:
        return sum(
            1 for d in psd_iter_days(s, e)
            if psd_day_weight(d, by_date) > 0
        )

    # ==========================================================
    # SUPABASE BOOKING READER FOR PROJECTED SALES DASHBOARD
    # Replaces old Google Sheet worksheet reader.
    # ==========================================================
    @st.cache_data(ttl=120)
    def psd_read_booking_data_cached(input_df: pd.DataFrame) -> Tuple[int, Dict[Tuple[int, int], int]]:
        """
        Returns:
            total_bookings,
            achieved_by_month {(year, month): count}
        Uses the prepared dataframe from Supabase.
        """
        if input_df is None or input_df.empty:
            return 0, {}

        temp = input_df.copy()

        if "Date" not in temp.columns:
            return 0, {}

        temp["Date"] = pd.to_datetime(temp["Date"], errors="coerce", dayfirst=True)

        temp = temp[temp["Date"].notna()]

        achieved_by_ym: Dict[Tuple[int, int], int] = {}

        for _, r in temp.iterrows():
            d = r["Date"]

            if pd.isna(d):
                continue

            ym = (int(d.year), int(d.month))
            achieved_by_ym[ym] = achieved_by_ym.get(ym, 0) + 1

        return len(temp), achieved_by_ym

    def psd_build_month_list(start: date, end: date) -> List[Tuple[int, int]]:
        out = []
        cur = psd_month_start(start)

        while cur <= end:
            out.append((cur.year, cur.month))
            cur = psd_next_month(cur)

        return out

    def psd_month_range(ym: Tuple[int, int], project_end: date) -> Tuple[date, date]:
        y, m = ym
        s = date(y, m, 1)
        e = min(project_end, psd_next_month(s) - timedelta(days=1))
        return s, e

    def psd_compute_month_targets_with_carry(month_list, month_weight, achieved_by_ym, total_target) -> Dict[Tuple[int, int], int]:
        targets: Dict[Tuple[int, int], int] = {}
        rem = int(total_target)

        for ym in month_list:
            w_this = month_weight.get(ym, 0.0)
            w_remaining = sum(
                month_weight.get(x, 0.0)
                for x in month_list
                if x >= ym
            )

            if rem <= 0 or w_remaining <= 0 or w_this <= 0:
                t = 0
            else:
                t = int(math.ceil(rem * (w_this / w_remaining)))

            targets[ym] = t
            rem = max(0, rem - int(achieved_by_ym.get(ym, 0)))

        return targets

