                f"<div class='metric-sub'>Lowest Avg Month ({low_month_2 or '—'}): {('—' if pd.isna(low_2) else f'₹{low_2:,.0f}/sqft')} &nbsp;|&nbsp; "
                f"Highest Avg Month ({high_month_2 or '—'}): {('—' if pd.isna(high_2) else f'₹{high_2:,.0f}/sqft')}</div>"
                f"</div>",
