        # ------------------------------------------------------------
        # Local safe helpers
        # ------------------------------------------------------------
        def _safe_str_series(series):
            """
            Safe string conversion for normal, numeric, datetime, and categorical columns.
            Fixes: TypeError when fillna("") is used on pandas Categorical columns.
            """
            if series is None:
                return pd.Series(dtype="object")
        
            # If duplicate column names return a DataFrame, take the first column safely
            if isinstance(series, pd.DataFrame):
                series = series.iloc[:, 0]
        
            s = pd.Series(series).astype("object")
            s = s.where(pd.notna(s), "")
        
            return s.apply(lambda x: str(x).strip())
    
        def _norm_status(v):
            return str(v or "").strip().lower()
    
        def _clean_options(series):
            cleaned = series.dropna().apply(lambda x: str(x).strip())
            return sorted([
                x for x in cleaned.unique().tolist()
                if x and x.upper() not in ("NAN", "NONE", "NULL")
            ])
    
        def _month_sort_key(x):
            parsed = pd.to_datetime(str(x), format="%B %y", errors="coerce")
            if pd.isna(parsed):
                parsed = pd.to_datetime(str(x), errors="coerce")
            return parsed if pd.notna(parsed) else pd.Timestamp.max
    
