        def stats_for(name: str):
            if tall.empty:
                return 0, 0, 0
    
            sub = tall[
                tall["offer"]
                .astype(str)
                .str.strip()
                .str.casefold()
                .eq(name.strip().casefold())
            ]
    
            total = int(len(sub))
            rewarded = int(sub["rewarded"].sum())
            pending = max(total - rewarded, 0)
    
            return total, rewarded, pending
    
