    # ---------- Helpers ----------
    def _norm_col(c: str) -> str:
        return (
            str(c or "")
            .strip()
            .lower()
            .replace(" ", "_")
            .replace("-", "_")
        )

    def _find_col(df_in: pd.DataFrame, candidates: list[str]):
        if df_in is None or df_in.empty:
            return None

        col_map = {_norm_col(c): c for c in df_in.columns}

        for cand in candidates:
            key = _norm_col(cand)
            if key in col_map:
                return col_map[key]

        return None

    def _clean_display_value(v):
        if pd.isna(v):
            return ""
        s = str(v).strip()
        if s.endswith(".0"):
            s = s[:-2]
        return s

    def _safe_pdf_text(s):
        s = str(s or "")
        replacements = {
            "₹": "Rs ",
            "—": "-",
            "–": "-",
            "•": "-",
            "“": '"',
            "”": '"',
            "‘": "'",
            "’": "'",
        }
        for a, b in replacements.items():
            s = s.replace(a, b)
        return s.encode("latin1", "ignore").decode("latin1")

    def _safe_filename(s):
        s = str(s or "").strip()
        for ch in '\\/:*?"<>|':
            s = s.replace(ch, "")
        return " ".join(s.split()) or "Civil_Changes"

