    # ============================================================
    # BASIC HELPERS
    # ============================================================
    def _safe_str(x):
        if x is None:
            return ""
        try:
            if pd.isna(x):
                return ""
        except Exception:
            pass
        s = str(x).strip()
        if s.endswith(".0"):
            s = s[:-2]
        return s

    def _norm_col(x):
        return re.sub(r"[^a-z0-9]+", "", str(x or "").lower())

    def _col(df: pd.DataFrame, *names):
        if df is None or df.empty:
            return None
        cmap = {_norm_col(c): c for c in df.columns}
        for name in names:
            key = _norm_col(name)
            if key in cmap:
                return cmap[key]
        return None

    def _to_num(x):
        try:
            if x is None:
                return 0.0
            try:
                if pd.isna(x):
                    return 0.0
            except Exception:
                pass
            s = (
                str(x)
                .replace("₹", "")
                .replace("Rs.", "")
                .replace("Rs", "")
                .replace(",", "")
                .strip()
            )
            if s == "":
                return 0.0
            return float(s)
        except Exception:
            return 0.0

    def _num_series(df, col):
        if df is None or df.empty or not col or col not in df.columns:
            return pd.Series(dtype=float)

        return pd.to_numeric(
            df[col]
            .astype("object")
            .where(pd.notna(df[col]), "")
            .astype(str)
            .str.replace("₹", "", regex=False)
            .str.replace("Rs.", "", regex=False)
            .str.replace("Rs", "", regex=False)
            .str.replace(",", "", regex=False),
            errors="coerce",
        ).fillna(0.0)

    def _fmt_money(x):
        return f"₹ {_to_num(x):,.0f}"

    def _fmt_num(x):
        return f"{_to_num(x):,.0f}"

    def _fmt_psf(x):
        if _to_num(x) <= 0:
            return "—"
        return f"₹ {_to_num(x):,.0f}/sqft"

    def _fmt_pct(x):
        try:
            if x is None or pd.isna(x):
                return "—"
            return f"{float(x):.1f}%"
        except Exception:
            return "—"

    def _pct(num, den):
        den = _to_num(den)
        num = _to_num(num)
        if den <= 0:
            return 0.0
        return (num / den) * 100.0

    def _is_agreement_done(v):
        s = _safe_str(v).lower()
        return s in {"done", "completed", "complete", "yes"} or "done" in s or "complete" in s

    def _is_stamp_received(v):
        # Business rule: blank = pending. Any meaningful remark/value = received.
        s = _safe_str(v).lower()
        if s in {"", "pending", "not received", "not recieved", "no", "n", "na", "n/a", "none"}:
            return False
        return True

    def _norm_wing(v):
        s = _safe_str(v).upper().replace("-", " ").replace("_", " ")
        s = " ".join(s.split())
        wing_map = {
            "B": "B Wing", "B WING": "B Wing",
            "C": "C Wing", "C WING": "C Wing",
            "E": "E Wing", "E WING": "E Wing",
            "F": "F Wing", "F WING": "F Wing",
        }
        return wing_map.get(s, _safe_str(v))

    def _norm_flat(v):
        return _safe_str(v).upper()

    def _parse_date(v):
        s = _safe_str(v).replace("'", "").strip()
        if not s:
            return pd.NaT

        if isinstance(v, (datetime.date, datetime.datetime, pd.Timestamp)):
            return pd.to_datetime(v, errors="coerce")

        formats = [
            "%d/%m/%Y", "%d/%m/%y",
            "%d-%m-%Y", "%d-%m-%y",
            "%Y-%m-%d",
            "%m/%d/%Y",
            "%d %b %Y", "%d %B %Y",
            "%B %y", "%b %y",
            "%B %Y", "%b %Y",
            "%Y-%m",
        ]

        for fmt in formats:
            try:
                return pd.Timestamp(datetime.datetime.strptime(s.title(), fmt))
            except Exception:
                pass

        try:
            return pd.to_datetime(s, dayfirst=True, errors="coerce")
        except Exception:
            return pd.NaT

    def _month_key_label_from_date(date_val):
        dt = _parse_date(date_val)
        if pd.isna(dt):
            return "9999-99", "UNKNOWN"
        return dt.strftime("%Y-%m"), dt.strftime("%B %y").upper()

    def _month_key_label_from_any(date_val=None, month_val=None):
        dt = _parse_date(date_val)
        if pd.notna(dt):
            return dt.strftime("%Y-%m"), dt.strftime("%B %y").upper()

        dt = _parse_date(month_val)
        if pd.notna(dt):
            return dt.strftime("%Y-%m"), dt.strftime("%B %y").upper()

        return "9999-99", "UNKNOWN"

    def _clean_email_list(v):
        if isinstance(v, str):
            return [x.strip() for x in v.split(",") if x.strip()]
        if isinstance(v, list):
            return [str(x).strip() for x in v if str(x).strip()]
        return []

    # ============================================================
    # SUPABASE READ HELPERS
    # ============================================================
    @st.cache_data(ttl=180, show_spinner=False)
    def _sb_select_all(table_name: str, order_col: str = "id") -> list[dict]:
        rows = []
        page_size = 1000
        start = 0

        while True:
            query = supabase_client.table(table_name).select("*")

            if order_col:
                try:
                    query = query.order(order_col)
                except Exception:
                    pass

            res = query.range(start, start + page_size - 1).execute()
            batch = getattr(res, "data", None) or []
            rows.extend(batch)

            if len(batch) < page_size:
                break

            start += page_size

        return rows

    def _load_table(table_name: str) -> pd.DataFrame:
        try:
            rows = _sb_select_all(table_name)
            df = pd.DataFrame(rows)
            if not df.empty:
                df.columns = [str(c).strip() for c in df.columns]
            return df
        except Exception as e:
            st.warning(f"Could not load `{table_name}`: {e}")
            return pd.DataFrame()

