    h_lineup_by_col = _col(holds_df, "agreement_lineup_by", "Agreement Lineup By")
    h_lineup_date_col = _col(holds_df, "agreement_lineup_date", "Agreement Lineup Date")

    if not holds_df.empty:
        holds_work = holds_df.copy()
